func (s *TransactionServer) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	// Validate request
	if req.Amount == nil || req.Amount.AmountMinorUnits <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "transaction amount must be positive")
	}
	if req.Amount.Currency == "" {
		return nil, status.Errorf(codes.InvalidArgument, "currency is required")
	}
	if req.IdempotencyKey == "" {
		return nil, status.Errorf(codes.InvalidArgument, "idempotency_key is required")
	}
	if req.Type == pb.TransactionType_UNKNOWN {
		return nil, status.Errorf(codes.InvalidArgument, "transaction type is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check idempotency
	if existingTxID, ok := s.idempotencyKeys[req.IdempotencyKey]; ok {
		existingTx := s.transactions[existingTxID]
		return &pb.CreateTransactionResponse{
			TransactionId: existingTxID,
			Status:        existingTx.Status,
			CreatedAt:     timestamppb.New(existingTx.CreatedAt),
			Message:       "duplicate request - returning existing transaction",
		}, nil
	}

	now := time.Now().UTC()
	txID := uuid.New().String()

	switch req.Type {
	case pb.TransactionType_DEPOSIT:
		if req.DestinationAccountId == "" {
			return nil, status.Errorf(codes.InvalidArgument, "destination_account_id is required for deposits")
		}
		destBalance, ok := s.balances[req.DestinationAccountId]
		if !ok {
			return nil, status.Errorf(codes.NotFound, "destination account %s not found", req.DestinationAccountId)
		}
		if destBalance.Currency != req.Amount.Currency {
			return nil, status.Errorf(codes.InvalidArgument, "currency mismatch: account currency is %s, transaction currency is %s", destBalance.Currency, req.Amount.Currency)
		}
		destBalance.AvailableMinorUnits += req.Amount.AmountMinorUnits

	case pb.TransactionType_WITHDRAWAL:
		if req.SourceAccountId == "" {
			return nil, status.Errorf(codes.InvalidArgument, "source_account_id is required for withdrawals")
		}
		srcBalance, ok := s.balances[req.SourceAccountId]
		if !ok {
			return nil, status.Errorf(codes.NotFound, "source account %s not found", req.SourceAccountId)
		}
		if srcBalance.Currency != req.Amount.Currency {
			return nil, status.Errorf(codes.InvalidArgument, "currency mismatch: account currency is %s, transaction currency is %s", srcBalance.Currency, req.Amount.Currency)
		}
		if srcBalance.AvailableMinorUnits < req.Amount.AmountMinorUnits {
			return nil, status.Errorf(codes.FailedPrecondition, "insufficient funds: available %d, requested %d", srcBalance.AvailableMinorUnits, req.Amount.AmountMinorUnits)
		}
		srcBalance.AvailableMinorUnits -= req.Amount.AmountMinorUnits

	case pb.TransactionType_TRANSFER:
		if req.SourceAccountId == "" || req.DestinationAccountId == "" {
			return nil, status.Errorf(codes.InvalidArgument, "both source_account_id and destination_account_id are required for transfers")
		}
		if req.SourceAccountId == req.DestinationAccountId {
			return nil, status.Errorf(codes.InvalidArgument, "source and destination accounts must be different")
		}
		srcBalance, ok := s.balances[req.SourceAccountId]
		if !ok {
			return nil, status.Errorf(codes.NotFound, "source account %s not found", req.SourceAccountId)
		}
		destBalance, ok := s.balances[req.DestinationAccountId]
		if !ok {
			return nil, status.Errorf(codes.NotFound, "destination account %s not found", req.DestinationAccountId)
		}
		if srcBalance.Currency != req.Amount.Currency {
			return nil, status.Errorf(codes.InvalidArgument, "currency mismatch with source account")
		}
		if destBalance.Currency != req.Amount.Currency {
			return nil, status.Errorf(codes.InvalidArgument, "currency mismatch with destination account")
		}
		if srcBalance.AvailableMinorUnits < req.Amount.AmountMinorUnits {
			return nil, status.Errorf(codes.FailedPrecondition, "insufficient funds: available %d, requested %d", srcBalance.AvailableMinorUnits, req.Amount.AmountMinorUnits)
		}
		srcBalance.AvailableMinorUnits -= req.Amount.AmountMinorUnits
		destBalance.AvailableMinorUnits += req.Amount.AmountMinorUnits

	default:
		return nil, status.Errorf(codes.InvalidArgument, "unsupported transaction type: %v", req.Type)
	}

	record := &TransactionRecord{
		ID:                   txID,
		SourceAccountID:      req.SourceAccountId,
		DestinationAccountID: req.DestinationAccountId,
		AmountMinorUnits:     req.Amount.AmountMinorUnits,
		Currency:             req.Amount.Currency,
		Type:                 req.Type,
		Status:               pb.TransactionStatus_COMPLETED,
		Description:          req.Description,
		Metadata:             req.Metadata,
		CreatedAt:            now,
		UpdatedAt:            now,
	}

	s.transactions[txID] = record
	s.idempotencyKeys[req.IdempotencyKey] = txID

	return &pb.CreateTransactionResponse{
		TransactionId: txID,
		Status:        pb.TransactionStatus_COMPLETED,
		CreatedAt:     timestamppb.New(now),
		Message:       fmt.Sprintf("transaction %s completed successfully", txID),
	}, nil
}

func (s *TransactionServer) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	if req.AccountId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	balance, ok := s.balances[req.AccountId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.AccountId)
	}

	if req.Currency != "" && req.Currency != balance.Currency {
		return nil, status.Errorf(codes.InvalidArgument, "requested currency %s does not match account currency %s", req.Currency, balance.Currency)
	}

	return &pb.GetBalanceResponse{
		AccountId: req.AccountId,
		AvailableBalance: &pb.Money{
			AmountMinorUnits: balance.AvailableMinorUnits,
			Currency:         balance.Currency,
		},
		PendingBalance: &pb.Money{
			AmountMinorUnits: balance.PendingMinorUnits,
			Currency:         balance.Currency,
		},
		AsOf: timestamppb.Now(),
	}, nil
}

func (s *TransactionServer) GetTransaction(ctx context.Context, req *pb.GetTransactionRequest) (*pb.GetTransactionResponse, error) {
	if req.TransactionId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "transaction_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	record, ok := s.transactions[req.TransactionId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "transaction %s not found", req.TransactionId)
	}

	return &pb.GetTransactionResponse{
		TransactionId:        record.ID,
		SourceAccountId:      record.SourceAccountID,
		DestinationAccountId: record.DestinationAccountID,
		Amount: &pb.Money{
			AmountMinorUnits: record.AmountMinorUnits,
			Currency:         record.Currency,
		},
		Type:        record.Type,
		Status:      record.Status,
		Description: record.Description,
		CreatedAt:   timestamppb.New(record.CreatedAt),
		UpdatedAt:   timestamppb.New(record.UpdatedAt),
		Metadata:    record.Metadata,
	}, nil
}